<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">python3</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -m</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> venv</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> ~/omni/venv</span></span>
